from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an airport (or related entity) into a single
    fluent English sentence.
    """
    if not triples:
        return ""

    # Assume all triples share the same subject (common for airport data)
    subject = triples[0].subject

    def phrase(t: Triple) -> str:
        p = t.predicate
        o = t.object
        # Simple template mapping for common predicates
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"is at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"is at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"is at an elevation of {o} metres above sea level"
        if p == "runwayLength":
            return f"has a runway length of {o} metres"
        if p.endswith("RunwayLengthFeet"):
            return f"has a runway length of {o} feet"
        if p.endswith("RunwayLengthMetre"):
            return f"has a runway length of {o} metres"
        if p.endswith("RunwayNumber"):
            return f"has runway number {o}"
        if p.endswith("RunwaySurfaceType"):
            return f"has a runway surface of {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        if p == "runwayName":
            return f"has runway named {o}"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "owner":
            return f"is owned by {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "iataLocationIdentifier":
            return f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"has ICAO code {o}"
        if p == "locationIdentifier":
            return f"has location identifier {o}"
        # Fallback generic phrasing
        return f"{p} {o}"

    # Build phrases for each triple
    parts = [phrase(t) for t in triples]

    # Join with commas and an 'and' before the last element
    if len(parts) == 1:
        body = parts[0]
    else:
        body = ", ".join(parts[:-1]) + ", and " + parts[-1]

    # Capitalize first letter and add period
    sentence = f"{subject} {body}."
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

